function parseAssignees(val) {
  // Returns an array of emails/usernames
  if (val === null || val === undefined || val === "" || val === "[]") return [];

  if (Array.isArray(val)) return val;

  if (typeof val === "string") {
    try {
      const parsed = JSON.parse(val);
      if (Array.isArray(parsed)) return parsed;
    } catch (e) {}
    // if it's some other string, treat it as a single value
    return [val];
  }

  return [String(val)];
}

function prettyAssignee(val) {
  const a = parseAssignees(val);
  if (!a.length) return "unknown";
  return a.join(", ");
}

function firstAssignee(val) {
  const a = parseAssignees(val);
  return a.length ? a[0] : null;
}

const POOL_USER = "helpdesk@local.test";

async function getAssignValueFresh(ticketName) {
  // Preferred: frappe.db.get_value
  if (frappe.db && frappe.db.get_value) {
    const r = await frappe.db.get_value("HD Ticket", ticketName, "_assign");
    return (r && r.message && r.message._assign) || "";
  }

  // Fallback
  const r = await frappe.call({
    method: "frappe.client.get_value",
    args: {
      doctype: "HD Ticket",
      filters: { name: ticketName },
      fieldname: ["_assign"],
    },
  });
  return (r && r.message && r.message._assign) || "";
}

function addClaimButton(frm) {
  frm.add_custom_button(
    __("Claim"),
    () => {
      frappe.call({
        method: "telephony.telectro_claim.telectro_claim_ticket",
        type: "POST",
        args: { ticket: frm.doc.name },
        freeze: true,
        callback: (r) => {
          const m = r.message || {};

          // ✅ Success path
          if (m.ok) {
            frappe.show_alert({ message: __("Claimed"), indicator: "green" });
            frm.reload_doc();
            return;
          }

          // ✅ Race/stale UI path: server replied "already_claimed" but assignee is the pool user
          const assigned = parseAssignees(m.assigned_to);
          const isPool = assigned.length === 1 && assigned[0] === POOL_USER;

          if (m.reason === "already_claimed" && isPool) {
            frappe.show_alert({
              message: __("Claim in progress… refreshing"),
              indicator: "orange",
            });
            frm.reload_doc();
            return;
          }

          // Normal "already claimed by another tech" path
          if (m.reason === "already_claimed") {
            frappe.msgprint(
              __("Already claimed: {0}", [prettyAssignee(m.assigned_to)])
            );
          } else {
            frappe.msgprint(__("Could not claim ticket."));
          }

          frm.reload_doc();
        },
      });
    },
    __("Actions")
  );
}

function addHandoffButton(frm) {
  frm.add_custom_button(
    __("Handoff"),
    () => {
      frappe.prompt(
        [
          {
              fieldname: "to_user",
              fieldtype: "Link",
              options: "User",
              label: __("Handoff to"),
              reqd: 1,
              get_query: () => ({
                filters: {
                  enabled: 1,
                  // optional: keep it tight; comment out if it blocks valid techs
                  // user_type: "System User",
                },
              }),
            },

          {
            fieldname: "reason",
            fieldtype: "Small Text",
            label: __("Reason"),
            reqd: 1, // friction: required
          },
        ],
        (values) => {
          const to_user = (values.to_user || "").trim();
          const reason = (values.reason || "").trim();

          frappe.call({
            method: "telephony.telectro_claim.telectro_handoff_ticket",
            type: "POST",
            args: { ticket: frm.doc.name, to_user, reason },
            freeze: true,
            callback: (r) => {
              const m = r.message || {};

              if (m.ok) {
                frappe.show_alert({
                  message: __("Handed off to {0}", [m.to || to_user]),
                  indicator: "green",
                });
                frm.reload_doc();
                return;
              }

              if (m.reason === "not_owner") {
                frappe.msgprint(__("Only the current assignee may handoff this ticket."));
                frm.reload_doc();
                return;
              }

              if (m.reason === "already_assigned") {
                frappe.msgprint(
                  __("Already assigned: {0}", [prettyAssignee(m.assigned_to)])
                );
                frm.reload_doc();
                return;
              }

              if (m.reason === "invalid_user") {
                frappe.msgprint(__("Invalid user: {0}", [m.to_user || to_user]));
                return;
              }

              frappe.msgprint(__("Could not handoff ticket."));
              frm.reload_doc();
            },
          });
        },
        __("Handoff Ticket"),
        __("Handoff")
      );
    },
    __("Actions")
  );
}

// ✅ NEW: Release back to pool (handoff to POOL_USER) with required reason
function addReleaseToPoolButton(frm) {
  frm.add_custom_button(
    __("Release to Pool"),
    () => {
      frappe.prompt(
        [
          {
            fieldname: "reason",
            fieldtype: "Small Text",
            label: __("Reason"),
            reqd: 1, // friction: required
          },
        ],
        (values) => {
          const reason = (values.reason || "").trim();

          frappe.call({
            method: "telephony.telectro_claim.telectro_handoff_ticket",
            type: "POST",
            args: { ticket: frm.doc.name, to_user: POOL_USER, reason },
            freeze: true,
            callback: (r) => {
              const m = r.message || {};

              if (m.ok) {
                frappe.show_alert({
                  message: __("Released to pool"),
                  indicator: "green",
                });
                frm.reload_doc();
                return;
              }

              if (m.reason === "not_owner") {
                frappe.msgprint(__("Only the current assignee may release this ticket."));
                frm.reload_doc();
                return;
              }

              frappe.msgprint(__("Could not release ticket."));
              frm.reload_doc();
            },
          });
        },
        __("Release Ticket"),
        __("Release")
      );
    },
    __("Actions")
  );
}

frappe.ui.form.on("HD Ticket", {
  async refresh(frm) {
    if (!frm.doc || !frm.doc.name) return;

    // Important: Helpdesk form does not include _assign in frm.doc, so fetch it.
    let assignVal = "";
    try {
      assignVal = await getAssignValueFresh(frm.doc.name);
    } catch (e) {
      return; // fail closed: avoid showing wrong buttons
    }

    const assignees = parseAssignees(assignVal);

    const is_unassigned = assignees.length === 0;
    const is_pool_owned = assignees.length === 1 && assignees[0] === POOL_USER;

    const claimable = is_unassigned || is_pool_owned;

    const owner = firstAssignee(assignVal);
    const is_owned_by_me = owner && owner === frappe.session.user;

    // Add buttons only when appropriate
    if (claimable) addClaimButton(frm);

    if (is_owned_by_me) {
      addHandoffButton(frm);
      addReleaseToPoolButton(frm); // ✅ NEW
    }
  },
});

// HD Ticket (List) — auto-refresh ONLY when viewing Faults
(function () {
  var TIMER_KEY = "__hd_faults_autorefresh_timer";
  var HANDLER_KEY = "__hd_faults_listupdate_handler";
  var TICK_N = 0;

  // Somewhere near PullFaults init scope:
    var rtHits = 0;

    // When attaching realtime:
    if (socket && socket.on) {
      console.log("[PullFaults] binding realtime list_update handler; socket.on exists=", true);

      socket.on("list_update", function (data) {
        rtHits += 1;
        console.log("[PullFaults] REALTIME HIT #" + rtHits, "data=", data);

        // Optional: if you want realtime to trigger refresh when in Faults view
        // (only do this if it doesn't spam)
        if (faultsView) {
          // call your internal refresh function here if you have one
          // e.g. refreshNow("realtime");
        }
      });

      console.log("[PullFaults] realtime handler attached");
    }


  var DEBUG = true;
  function dbg() {
    if (DEBUG && window.console) {
      console.log.apply(console, ["[PullFaults]"].concat([].slice.call(arguments)));
    }
  }

  function getFilters(listview) {
    try {
      if (listview && listview.filter_area && listview.filter_area.get) {
        return listview.filter_area.get() || [];
      }
      return [];
    } catch (e) {
      return [];
    }
  }

  function toLowerStr(v) {
    if (v === null || v === undefined) return "";
    return String(v).toLowerCase();
  }

  function matchFaultsFilter(fieldname, opRaw, valRaw) {
    var op = toLowerStr(opRaw);
    var val = toLowerStr(valRaw);

    // exactly the Faults Console filter
    if (fieldname !== "custom_service_area") return false;
    if (op !== "=") return false;
    return val === "faults";
  }

  function isFaultsView(listview) {
    var filters = getFilters(listview);
    // filters often look like: [doctype, fieldname, operator, value, hidden?]
    for (var i = 0; i < filters.length; i++) {
      var f = filters[i];
      if (!f || f.length < 4) continue;

      // f[0] doctype; f[1] fieldname; f[2] operator; f[3] value
      if (f[0] === "HD Ticket" && matchFaultsFilter(f[1], f[2], f[3])) return true;
    }
    return false;
  }

  function debounce(fn, ms) {
    var t = null;
    return function () {
      var args = arguments;
      clearTimeout(t);
      t = setTimeout(function () {
        try {
          fn.apply(null, args);
        } catch (e) {}
      }, ms);
    };
  }

  function clearTimer() {
    if (window[TIMER_KEY]) {
      clearInterval(window[TIMER_KEY]);
      window[TIMER_KEY] = null;
    }
  }

  function clearRealtimeHandler() {
    var h = window[HANDLER_KEY];
    if (!h) return;

    try {
      if (window.frappe && frappe.realtime && frappe.realtime.socket && frappe.realtime.socket.off) {
        frappe.realtime.socket.off("list_update", h);
      }
    } catch (e) {}
    window[HANDLER_KEY] = null;
  }

  // ✅ Important: only call this when listview exists (inside start/onload)
  function postLoadCheck(listview) {
    setTimeout(function () {
      try {
        dbg("post-load check; faultsView=", isFaultsView(listview), "filters=", getFilters(listview));
      } catch (e) {}
    }, 1500);
  }

  function start(listview) {
    clearTimer();
    clearRealtimeHandler();

    TICK_N = 0;

    var safeRefresh = debounce(function () {
      try {
        if (isFaultsView(listview)) {
          listview.refresh();
        }
      } catch (e) {}
    }, 1000);

    dbg("start() called; faultsView=", isFaultsView(listview), "filters=", getFilters(listview));

    // ✅ runs after listview exists (fixes "listview is not defined")
    postLoadCheck(listview);

    // Light poll: only refresh when Faults filter is active
    window[TIMER_KEY] = setInterval(function () {
      TICK_N += 1;
      if (!isFaultsView(listview)) return;
      safeRefresh();
      dbg("tick#", TICK_N, "faultsView=true");
    }, 15000);

    // Realtime: refresh quickly when tickets update (still scoped to Faults view)
    try {
      if (window.frappe && frappe.realtime && frappe.realtime.socket && frappe.realtime.socket.on) {
        dbg("binding realtime list_update handler; socket.on exists=", true);

        var handler = function (data) {
          dbg("realtime list_update raw=", data);
          if (!data || data.doctype !== "HD Ticket") return;
          dbg("realtime list_update (HD Ticket) name=", data.name);
          safeRefresh();
        };

        window[HANDLER_KEY] = handler;
        frappe.realtime.socket.on("list_update", handler);

        dbg("realtime handler attached");
      } else {
        dbg("realtime not available; no handler bound");
      }
    } catch (e) {
      dbg("realtime bind error", e);
    }


    // Cleanup when leaving the list page
    try {
      if (listview && listview.page && listview.page.on) {
        listview.page.on("hide", function () {
          clearTimer();
          clearRealtimeHandler();
        });
      }
    } catch (e) {}
  }

  // Hook listview onload safely (preserve prior onload)
  frappe.listview_settings["HD Ticket"] = frappe.listview_settings["HD Ticket"] || {};
  var prevOnload = frappe.listview_settings["HD Ticket"].onload;

  frappe.listview_settings["HD Ticket"].onload = function (listview) {
    try {
      if (prevOnload) prevOnload(listview);
    } catch (e) {}
    start(listview);
  };
})();

frappe.ui.form.on(
  "HD Ticket",
  (() => {
    const DEFAULTS = {
      custom_fault_category: "Buildings",
      custom_service_area: "Other",
      custom_severity: "Sev3",
    };

    function geom_for_category(cat) {
      const c = (cat || "").trim();
      if (c === "Links") return "LineString";
      if (c === "Areas") return "Polygon";
      return "Point";
    }

    function is_non_point_category(cat) {
      const c = (cat || "").trim();
      return c === "Links" || c === "Areas";
    }

    function sync_point_fields(frm) {
      const nonPoint = is_non_point_category(frm.doc.custom_fault_category);

      // Asset is always visible for non-point categories; hidden for point categories
      frm.toggle_display("custom_fault_asset", nonPoint);
      frm.toggle_reqd("custom_fault_asset", nonPoint);

      // Fault Point is dispatch anchor: disable for Links/Areas
      frm.toggle_enable("custom_site", !nonPoint);

      if (!nonPoint) {
        // Point categories: mirror Asset = Point (for reporting)
        if (
          frm.doc.custom_site &&
          frm.doc.custom_fault_asset !== frm.doc.custom_site
        ) {
          frm.set_value("custom_fault_asset", frm.doc.custom_site);
        }
      } else {
        // Non-point categories: keep Point empty to avoid bad anchors
        if (frm.doc.custom_site) frm.set_value("custom_site", null);
      }
    }

    function reset_dependents(frm) {
      if (frm.doc.custom_site) frm.set_value("custom_site", null);
      if (frm.doc.custom_fault_asset) frm.set_value("custom_fault_asset", null);
    }

    function set_queries(frm) {
      frm.set_query("custom_site_group", () => ({
        filters: { parent_location: "Pilot Sites", is_group: 1 },
        page_length: 50,
      }));

      // Fault Point (dispatch anchor) = Point only
      frm.set_query("custom_site", () => {
        const campus = frm.doc.custom_site_group;
        const cat = frm.doc.custom_fault_category;
        if (!campus || !cat) return { filters: { name: "__never__" } };

        return {
          filters: {
            parent_location: `${campus} - ${cat}`,
            is_group: 0,
            custom_kmz_geometry_type: "Point",
          },
          page_length: 50,
        };
      });

      // Fault Asset (thing that failed) = geometry depends on category
      frm.set_query("custom_fault_asset", () => {
        const campus = frm.doc.custom_site_group;
        const cat = frm.doc.custom_fault_category;
        if (!campus || !cat) return { filters: { name: "__never__" } };

        return {
          filters: {
            parent_location: `${campus} - ${cat}`,
            is_group: 0,
            custom_kmz_geometry_type: geom_for_category(cat),
          },
          page_length: 50,
        };
      });
    }

    function refresh_deps(frm) {
      try {
        frm.layout?.refresh_dependency?.();
      } catch (e) {}

      frm.refresh_field("custom_fault_category");
      frm.refresh_field("custom_site");
      frm.refresh_field("custom_fault_asset");
    }

    async function apply_campus_defaults(frm) {
      if (!frm.doc.custom_site_group) return;

      const tasks = [];

      if (!frm.doc.custom_fault_category) {
        tasks.push(
          frm.set_value(
            "custom_fault_category",
            DEFAULTS.custom_fault_category,
          ),
        );
      }
      if (!frm.doc.custom_service_area) {
        tasks.push(
          frm.set_value("custom_service_area", DEFAULTS.custom_service_area),
        );
      }
      if (!frm.doc.custom_severity) {
        tasks.push(frm.set_value("custom_severity", DEFAULTS.custom_severity));
      }

      if (tasks.length) await Promise.all(tasks);

      refresh_deps(frm);
    }

    async function map_customer_to_campus(frm) {
      const customer = frm.doc.custom_customer;
      if (!customer) return;

      try {
        const r = await frappe.db.get_value(
          "Customer",
          customer,
          "custom_default_campus",
        );
        const campus = r?.message?.custom_default_campus;
        if (campus && campus !== frm.doc.custom_site_group) {
          await frm.set_value("custom_site_group", campus);
        }
      } catch (e) {}
    }

    return {
      async refresh(frm) {
        set_queries(frm);
        await apply_campus_defaults(frm);
        sync_point_fields(frm);
        refresh_deps(frm);
      },

      before_save(frm) {
        if (!frm.is_new()) return;
        if (frm.doc.summary) return;
        if (frm.doc.subject) frm.set_value("summary", frm.doc.subject);
      },

      async custom_site_group(frm) {
        reset_dependents(frm);
        await apply_campus_defaults(frm);
        sync_point_fields(frm);
        refresh_deps(frm);
      },

      custom_fault_category(frm) {
        reset_dependents(frm);
        sync_point_fields(frm);
        refresh_deps(frm);
      },

      async custom_customer(frm) {
        reset_dependents(frm);

        if (frm.doc.custom_fault_category)
          frm.set_value("custom_fault_category", null);
        if (frm.doc.custom_site_group) frm.set_value("custom_site_group", null);

        if (frm.doc.custom_service_area)
          frm.set_value("custom_service_area", null);
        if (frm.doc.custom_severity) frm.set_value("custom_severity", null);

        await map_customer_to_campus(frm);
        await apply_campus_defaults(frm);
        refresh_deps(frm);
      },
      custom_site(frm) {
        // if this is a point category, mirror the asset field
        if (!is_non_point_category(frm.doc.custom_fault_category)) {
          if (
            frm.doc.custom_site &&
            frm.doc.custom_fault_asset !== frm.doc.custom_site
          ) {
            frm.set_value("custom_fault_asset", frm.doc.custom_site);
          }
        }
      },
    };
  })(),
);

frappe.ui.form.on("HD Ticket", {
  refresh(frm) {
    frm.trigger("telectro_ticket_type_ux");
  },
  ticket_type(frm) {
    frm.trigger("telectro_ticket_type_ux");
  },

  telectro_ticket_type_ux(frm) {
    const t = (frm.doc.ticket_type || "").trim();

    const faultLike = ["Faults", "Incident"].includes(t);
    const requestLike = !faultLike; // treat everything else as request-like for pilot

    const requestFields = ["custom_request_type", "custom_requested_by", "custom_due_date"];
    const faultFields = [
      "custom_fault_category",
      "custom_fault_asset",
      "custom_site_group",
      "custom_site",
      "custom_service_area",
      "custom_severity",
    ];

    const faultHasData = faultFields.some((f) => {
      const v = frm.doc[f];
      return v !== undefined && v !== null && String(v).trim() !== "";
    });

    const showFaultFields = faultLike || faultHasData;

    requestFields.forEach((f) => frm.toggle_display(f, requestLike));
    faultFields.forEach((f) => frm.toggle_display(f, showFaultFields));

    frm.toggle_reqd("custom_request_type", requestLike);

    frm.dashboard.clear_headline_alert();
    if (requestLike) {
      frm.dashboard.set_headline_alert(
        "Request mode: capture what is needed (type, requester, due date). Fault-specific fields are hidden unless already filled.",
        "blue"
      );
    } else {
      frm.dashboard.set_headline_alert(
        "Fault mode: capture category, severity, service area and a valid site/location.",
        "orange"
      );
    }
  },
});
